    suppressWarnings() |&gt;
    tibble::as_tibble()
  names(preds) &lt;- paste("pred", names(preds), sep = "_")
  dplyr::bind_cols(data, cis, preds) |&gt;
    ggplot2::ggplot() +
    ggplot2::aes(
